SET search_path = SCHEMA_NAME, public, pg_catalog;
UPDATE config_report AS t SET filterparam = v.text::json FROM (
	VALUES
	(100, '[{"label": "Експлуатація:", "datatype": "text", "columnname": "Exploitation", "widgettype": "combo", "dvquerytext": "Select name as id, name as idval FROM exploitation WHERE expl_id > 0 ORDER BY name", "isNullValue": "true", "layoutorder": 1}, {"label": "Каталог Дуг:", "datatype": "text", "columnname": "Arc Catalog", "widgettype": "combo", "dvquerytext": "Select id as id, id as idval FROM cat_arc WHERE id IS NOT NULL ORDER BY id", "isNullValue": "true", "layoutorder": 2}]'),
    (101, '[{"label": "Експлуатація:", "datatype": "text", "columnname": "expl_id", "widgettype": "combo", "dvquerytext": "Select expl_id as id, name as idval FROM exploitation WHERE expl_id IS NOT NULL", "isNullValue": "true", "layoutorder": 1}]'),
    (105, '[{"label": "Експлуатація:", "datatype": "text", "columnname": "Exploitation", "widgettype": "combo", "dvquerytext": "Select name as id, name as idval FROM exploitation WHERE expl_id > 0 ORDER BY name", "isNullValue": "true", "layoutorder": 1}, {"label": "Тип вузла:", "datatype": "text", "columnname": "Node type", "widgettype": "combo", "dvquerytext": "Select id as id, id as idval FROM cat_feature_node join cat_feature USING (id) WHERE id IS NOT NULL AND active ORDER BY id", "isNullValue": "true", "layoutorder": 2}]')
) AS v(id, text)
WHERE t.id = v.id;

UPDATE config_toolbox AS t SET inputparams = v.text::json FROM (
	VALUES
	(2768, '[{"label": "Graph class:", "tooltip": "Graphanalytics method used", "comboIds": ["DWFZONE", "SECTOR", "DMA"], "datatype": "text", "comboNames": ["Дренажна площа (DRAINZONE + DWFZONE)", "СЕКТОР", "DMA"], "layoutname": "grl_option_parameters", "selectedId": null, "widgetname": "graphClass", "widgettype": "combo", "layoutorder": 1}, {"label": "Exploitation:", "tooltip": "Choose exploitation to work with", "datatype": "text", "layoutname": "grl_option_parameters", "selectedId": null, "widgetname": "exploitation", "widgettype": "combo", "dvQueryText": "SELECT id, idval FROM ( SELECT -901 AS id, ''User selected expl'' AS idval, ''a'' AS sort_order UNION SELECT -902 AS id, ''All exploitations'' AS idval, ''b'' AS sort_order UNION SELECT expl_id AS id, name AS idval, ''c'' AS sort_order FROM exploitation WHERE active IS NOT FALSE AND expl_id > 0 ) a ORDER BY sort_order ASC, idval ASC", "layoutorder": 2}, {"label": "Примусово відкриті дуги: (*)", "value": null, "tooltip": "Опційні id(и) дуг для тимчасового відкриття закритих дуг, щоб змусити алгоритм продовжити там", "datatype": "text", "layoutname": "grl_option_parameters", "widgetname": "forceOpen", "widgettype": "linetext", "isMandatory": false, "layoutorder": 5, "placeholder": "1015,2231,3123"}, {"label": "Примусово закриті дуги: (*)", "value": null, "tooltip": "Опційні id(и) дуг для тимчасового закриття відкритих дуг, щоб змусити алгоритм зупинитися там", "datatype": "text", "layoutname": "grl_option_parameters", "widgetname": "forceClosed", "widgettype": "text", "isMandatory": false, "layoutorder": 6, "placeholder": "1015,2231,3123"}, {"label": "Use selected psectors:", "value": null, "tooltip": "If true, use selected psectors. If false ignore selected psectors and only works with on-service network", "datatype": "boolean", "layoutname": "grl_option_parameters", "widgetname": "usePlanPsector", "widgettype": "check", "layoutorder": 7}, {"label": "Commit changes:", "value": null, "tooltip": "If true, changes will be applied to DB. If false, algorithm results will be saved in anl tables", "datatype": "boolean", "layoutname": "grl_option_parameters", "widgetname": "commitChanges", "widgettype": "check", "layoutorder": 8}, {"label": "Mapzone constructor method:", "comboIds": [0, 1, 2, 6], "datatype": "integer", "comboNames": ["ЖОДЕН", "УГНУТИЙ БАГАТОКУТНИК", "БУФЕР ТРУБИ", "EPA SUBCATCH"], "layoutname": "grl_option_parameters", "selectedId": null, "widgetname": "updateMapZone", "widgettype": "combo", "layoutorder": 10}, {"label": "Pipe buffer", "value": null, "tooltip": "Buffer from arcs to create mapzone geometry using [PIPE BUFFER] options. Normal values maybe between 3-20 mts.", "datatype": "float", "layoutname": "grl_option_parameters", "widgetname": "geomParamUpdate", "widgettype": "text", "isMandatory": false, "layoutorder": 11, "placeholder": "5-30"}, {"label": "Картозони з нуля:", "value": null, "tooltip": "Якщо true, картозони обчислюються автоматично з нуля", "datatype": "boolean", "layoutname": "grl_option_parameters", "widgetname": "fromZero", "widgettype": "check", "layoutorder": 12}]'),
    (3100, '[{"label": "Ціль:", "value": null, "datatype": "text", "layoutname": "grl_option_parameters", "selectedId": null, "widgetname": "target", "widgettype": "combo", "dvQueryText": "SELECT distinct(hydrology_id) as id, name as idval FROM cat_hydrology WHERE active IS TRUE", "layoutorder": 1}, {"label": "Сектор:", "value": null, "datatype": "text", "layoutname": "grl_option_parameters", "selectedId": null, "widgetname": "sector", "widgettype": "combo", "dvQueryText": "SELECT sector_id AS id, name as idval FROM sector JOIN selector_sector USING (sector_id) WHERE cur_user = current_user UNION SELECT -999,''ALL VISIBLE SECTORS'' ORDER BY 1 DESC", "layoutorder": 2}, {"label": "Дія:", "value": null, "comboIds": ["DELETE-COPY", "KEEP-COPY", "DELETE-ONLY"], "datatype": "text", "comboNames": ["ВИДАЛИТИ & КОПІЮВАТИ", "ЗБЕРЕГТИ & КОПІЮВАТИ", "ТІЛЬКИ ВИДАЛИТИ"], "layoutname": "grl_option_parameters", "selectedId": null, "widgetname": "action", "widgettype": "combo", "layoutorder": 3}, {"label": "Копіювати з:", "value": null, "datatype": "text", "layoutname": "grl_option_parameters", "selectedId": null, "widgetname": "copyFrom", "widgettype": "combo", "dvQueryText": "SELECT distinct(hydrology_id) as id, name as idval FROM cat_hydrology WHERE active IS TRUE", "layoutorder": 4}]'),
